SELECT count(*) FROM cast_info, name, title, role_type, movie_companies, aka_name, kind_type, company_type, company_name WHERE cast_info.person_id = name.id AND cast_info.movie_id = title.id AND cast_info.role_id = role_type.id AND movie_companies.movie_id = title.id AND aka_name.person_id = name.id AND title.kind_id = kind_type.id AND movie_companies.company_type_id = company_type.id AND movie_companies.company_id = company_name.id;